// --- Finalize Response ---
// Mode: Run Once for All Items
// 입력: 앞 노드(Price Parse & Merge)에서 아이템 스트림
// 출력: ok/errors/summary/groups[0] (groups[0] 상단에 buyer 보존)

function toNum(v, d = 0) {
  const n = Number(String(v ?? '').replace(/[^\d.-]/g, ''));
  return Number.isFinite(n) ? n : d;
}
function toInt(v, d = 0) {
  const n = parseInt(String(v ?? '').replace(/[^\d-]/g, ''), 10);
  return Number.isFinite(n) ? n : d;
}
function pick(obj, keys) {
  for (const k of keys) {
    const v = obj && obj[k];
    if (v !== undefined && v !== null && String(v).trim() !== '') return String(v);
  }
  return '';
}

// 0) 입력 아이템 수집
const arr = $items().map(i => i.json || {});

// abort 패스스루
const abort = arr.find(x => x && x.__abort);
if (abort) {
  return [{ json: abort }];
}

// 1) buyer 추출 — 오직 item.buyer에서만!
//    어떤 경우에도 아이템 루트의 name(상품명) 등을 구매자 이름으로 쓰지 않음.
function extractBuyerFromItems(items) {
  // buyer 정보가 가장 풍부한 첫 아이템의 buyer를 우선 사용
  const withBuyer = items.find(x =>
    x.buyer && (
      x.buyer.name || x.buyer.phone || x.buyer.email || x.buyer.address ||
      x.buyer.memo || x.buyer.note || x.buyer.notes
    )
  );
  const b = (withBuyer && withBuyer.buyer) || {};

  // 필요한 필드만 엄격 추출 (루트 필드로는 절대 보강하지 않음)
  return {
    name:    pick(b, ['name','buyer_name','customer_name','이름']) || '',
    phone:   pick(b, ['phone','tel','mobile','전화','전화번호'])   || '',
    email:   pick(b, ['email','mail','이메일'])                    || '',
    address: pick(b, ['address','addr','주소'])                    || '',
    memo:    pick(b, ['memo','note','notes'])                      || '',
  };
}

const buyer = extractBuyerFromItems(arr);

// 2) 라인 계산(이중 할인 금지: total = price × qty)
const errors = [];
const lines = arr.map((x, idx) => {
  const qty    = Math.max(1, toInt(x.qty, 1));
  const unit   = toNum(x.price, 0);                 // 최종 단가(Price Parse & Merge에서 확정)
  const oprice = toNum(x.original_price, 0) || null; // 소비자가(정가)
  const lprice = toNum(x.listed_price, 0)   || null; // 페이지 표시가(참고)
  const dprice = (x.display_price != null) ? toNum(x.display_price, null) : (oprice || lprice);

  const total  = unit ? Math.round(unit * qty) : 0;  // ★ 절대 퍼센트 재적용 금지

  if (!unit) errors.push({ message: `가격 추출 실패: #${(x.item_idx ?? idx) + 1}` });

  // 표시용 할인 라벨
  let discount_label = '0%';
  const rateNum = toNum(x.discount_rate, 0);
  if (x.discount_mode === 'fixed') discount_label = '고정';
  else if (rateNum > 0) discount_label = `${rateNum}%`;

  return {
    product_url    : String(x.product_url || ''),
    name           : String(x.name || ''),
    qty            : qty,
    price          : unit,                 // 최종 단가(실결제가)
    original_price : oprice,               // 소비자가(정가)
    listed_price   : lprice,               // 참고
    display_price  : dprice,               // 프런트 "가격" 칼럼에 사용(= original || listed)
    discount_mode  : x.discount_mode || null,
    discount_rate  : rateNum,              // 숫자(퍼센트). 고정가면 0
    discount_label : discount_label,       // '고정' | 'NN%' | '0%'
    size           : x.size || '',
    notes          : x.notes || '',
    item_idx       : x.item_idx ?? idx,
    total          : total,                // ★ 소계 = price × qty

    supply_rate    : Number(x.supply_rate || 0),
    supply_price   : Number(x.supply_price || 0),

    // 가격 계산/매칭 디버그 정보 보존 (Price Parse & Merge에서 전달)
    price_found    : (x.price_found !== undefined) ? x.price_found : (Number(unit) > 0),
    match_debug    : (x.match_debug !== undefined) ? x.match_debug : null
  };
});

// 3) 요약 합계
const items_total    = lines.reduce((s, v) => s + (v.total || 0), 0);
const qty_total      = lines.reduce((s, v) => s + (v.qty   || 0), 0);
const shipping_total = Math.ceil(qty_total / 3) * 3500; // 3개당 3,500원
const grand_total    = items_total + shipping_total;

// 4) 최종 구조 (buyer를 group 최상단에 보존)
return [{
  json: {
    ok: errors.length === 0,
    errors,
    summary: {
      items_total,
      shipping_total,
      group_count: 1,
      grand_total,
    },
    groups: [
      {
        group_idx: 0,
        // 주문자 정보 — 비워두면 그대로 빈 값 유지
        name:    buyer.name,
        phone:   buyer.phone,
        email:   buyer.email,
        address: buyer.address,
        memo:    buyer.memo,
        // 아이템 배열
        items: lines
      }
    ]
  }
}];

// --- FLATTEN (Run Once for All Items) ---
// 목적: 주문자 + 아이템을 "아이템당 1개" 스트림으로 전개
// - 프런트 신규 필드: discount_mode('percent'|'fixed'), discount_value, fixed_price 지원
// - 구버전 필드: discount_rate(%)도 자동 호환
// - URL 검증, 최소 1개 아이템 미만일 때 __abort로 중단

// 0) 입력 본문 안전하게 잡기 (Webhook1에서 직접 가져옴 - Google Sheets가 중간에 있어서 변경됨)
// [수정됨] 바로 앞 노드(Google Sheets) 데이터가 아니라, 맨 처음 Webhook1 데이터를 직접 참조합니다.
const webhookData = $('Webhook1').first().json;
const body = webhookData.body ?? webhookData;

const groups = Array.isArray(body.groups) ? body.groups : [];

// 유틸
const toNum = (v, d=0) => {
  const n = Number(String(v ?? '').replace(/[^\d.-]/g,''));
  return Number.isFinite(n) ? n : d;
};
const toInt = (v, d=0) => {
  const n = parseInt(String(v ?? '').replace(/[^\d-]/g,''), 10);
  return Number.isFinite(n) ? n : d;
};
const pick = (obj, keys) => {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== '') return String(v).trim();
  }
  return '';
};

const out = [];
const errors = [];

groups.forEach((g, gi) => {
  // 1) 주문자 정보(그룹 우선, 없으면 body에서 보강)
  const buyer = {
    name:    pick(g, ['name','buyer_name','customer_name','이름'])    || pick(body, ['name','buyer_name','customer_name','이름']),
    phone:   pick(g, ['phone','tel','mobile','전화','전화번호'])      || pick(body, ['phone','tel','mobile','전화','전화번호']),
    email:   pick(g, ['email','mail','이메일'])                       || pick(body, ['email','mail','이메일']),
    address: pick(g, ['address','addr','주소'])                       || pick(body, ['address','addr','주소']),
    memo:    pick(g, ['memo','note','notes','요청사항'])              || pick(body, ['memo','note','notes','요청사항']),
  };

  // 2) 아이템 전개
  const items = Array.isArray(g?.items) ? g.items : [];
  items.forEach((it, ii) => {
    const url  = String(it?.product_url ?? '').trim();
    const product_mode = String(it?.product_mode ?? (it?.manual_keyword ? 'manual' : 'url')).trim().toLowerCase();
    const manual_keyword = String(it?.manual_keyword ?? '').trim();
    const qty  = Math.max(1, toInt(it?.qty ?? it?.quantity ?? 1, 1));
    const size = it?.size ?? it?.options?.size ?? it?.variant ?? it?.selectedSize ?? '';
    const notes = it?.notes ?? '';

    // 할인 필드(신버전/구버전 호환)
    const modeRaw  = it?.discount_mode || null;                 // 'percent' | 'fixed' | null
    const valRaw   = toNum(it?.discount_value || 0);            // 퍼센트값 또는 고정가
    const fixedRaw = toNum(it?.fixed_price || 0);
    const rateRaw  = (it?.discount_rate !== undefined && it?.discount_rate !== null && String(it?.discount_rate).trim() !== '')
                      ? toInt(it?.discount_rate, 0)
                      : null;

    // 최종 정규화
    let discount_mode   = null;   // 'percent' | 'fixed' | null
    let discount_value  = 0;      // percent or fixed
    let fixed_price     = 0;      // 고정가
    let discount_rate   = null;   // % 표시용(백엔드/카드 용이성)

    if (modeRaw === 'fixed' || fixedRaw > 0) {
      discount_mode  = 'fixed';
      fixed_price    = fixedRaw || valRaw;   // 프런트가 discount_value에 고정가를 넣는 경우 고려
      discount_value = fixed_price;
      discount_rate  = null;                 // 퍼센트 없음
    } else if (modeRaw === 'percent' || rateRaw !== null) {
      discount_mode  = 'percent';
      discount_rate  = (modeRaw === 'percent') ? toInt(valRaw, 0) : rateRaw;
      discount_value = discount_rate;
    } else {
      // 명시된 할인 없음
      discount_mode = null;
      discount_value = 0;
      discount_rate = null;
    }

    // URL 검증 (사전 판매(manual) 상품은 URL이 없으므로 건너뜀)
    if (product_mode !== 'manual' && !/^https?:\/\//i.test(url)) {
      errors.push({ message: `#${ii + 1} URL 형식 오류` });
    }

    out.push({
      group_idx: gi,
      item_idx: ii,
      buyer,
      product_url: url,
      product_mode,
      manual_keyword,
      qty,
      size,
      notes,

      // 할인 관련(신/구 모두 유지해 다음 노드에서 활용)
      discount_mode,
      discount_value,
      fixed_price,
      discount_rate,
    });
  });
});

// 3) 아이템이 하나도 없을 때: abort 플래그로 이후 노드 보호
if (!out.length) {
  return [{
    json: {
      __abort: true,
      ok: false,
      errors: errors.length ? errors : [{ message: '최소 1개 이상의 상품을 추가하세요.' }],
      groups: [{ group_idx: 0, items: [] }],
      summary: { items_total: 0, shipping_total: 0, group_count: 1, grand_total: 0 },
    }
  }];
}

// 4) 아이템 스트림 반환(검증 에러는 이후 단계에서 표시)
return out.map(x => ({ json: x }));

// --- Price Parse & Merge (Smart Auto Discount & Precision Crawling) ---
// 모드: Run Once for Each Item

// --- 유틸리티 ---
function num(v, d = null) {
  const n = Number(String(v ?? '').replace(/[^\d.-]/g, ''));
  return Number.isFinite(n) ? n : d;
}
function num0(v) { return num(v, 0); }

function stripTags(html) {
  return String(html ?? '')
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}
function decode(s) {
  return String(s ?? '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&#39;/g, "'");
}

// --- 1. 이름 정밀 파싱 (불필요한 태그 완벽 제외) ---
function parseName(html) {
  let m = html.match(/<div[^>]*class=["'][^"']*headingArea[^"']*["'][^>]*>\s*<h1[^>]*>([\s\S]*?)<\/h1>/i);
  if (m) return decode(stripTags(m[1])).trim(); 

  m = html.match(/<h1[^>]*>([\s\S]*?)<\/h1>/i);
  if (m) return decode(stripTags(m[1])).trim();

  m = html.match(/<meta[^>]+property=["']og:title["'][^>]+content=["']([^"']+)["']/i);
  if (m) return decode(m[1]).trim();

  return '';
}

// --- 2. 브랜드명 스마트 제거 ---
function cleanBrandName(name = '') {
  const brandPattern = '(?:온유어마크|On\\s?Your\\s?Mark|onyourmark(?:-running)?\\.com)(?:\\s*(?:공식)?\\s*온라인\\s*스토어|\\s*스토어|\\s*SHOP|\\s*몰)?';
  let s = String(name);
  const prefixRe = new RegExp(`^\\s*${brandPattern}\\s*[\\-|–—\\|·•]\\s*`, 'i');
  s = s.replace(prefixRe, '');
  const suffixRe = new RegExp(`\\s*[\\-|–—\\|·•]\\s*${brandPattern}\\s*$`, 'i');
  s = s.replace(suffixRe, '');
  const parenRe = new RegExp(`\\s*\\(${brandPattern}[^)]*\\)\\s*$`, 'i');
  s = s.replace(parenRe, '');
  return s.replace(/\s+/g, ' ').trim();
}

// --- 3. 상품코드 전방위 수색 (함수명 extractSKU로 통일) ---
function extractSKU(html, currentName) {
  // 1순위: 이름 안에 괄호가 있는지 확인
  const nameMatch = currentName.match(/\(([^)]+)\)$/);
  if (nameMatch) return nameMatch[1].trim();

  // 패턴 A: <th> 태그와 실제 코드 사이의 거리가 멀어 못 찾는 현상 해결 (수색 거리 300자 -> 2000자로 대폭 확장)
  let m = html.match(/<th[^>]*>\s*(?:코드|상품코드)\s*<\/th>[\s\S]{0,2000}?<li[^>]*title=["']([a-zA-Z0-9_-]{4,30})["']/i);
  if (m) return m[1].toUpperCase();

  // 패턴 B: span 태그로 감싸진 경우도 거리 2000자로 확장
  m = html.match(/<th[^>]*>\s*(?:코드|상품코드)\s*<\/th>[\s\S]{0,2000}?<span[^>]*>([a-zA-Z0-9_-]{4,30})<\/span>/i);
  if (m) return m[1].toUpperCase();

  // 패턴 C: 기존 범용 테이블 (단, option이라는 단어가 섞여 있으면 무시)
  const tablePatterns = [
    /<th[^>]*>\s*(?:상품코드|코드|모델명|품번|Product\s*Code)\s*<\/th>\s*<td[^>]*>\s*(?:<p[^>]*>)?\s*([a-zA-Z0-9_-]{4,30})\s*(?:<\/p>)?\s*<\/td>/i,
    /item_code\s*=\s*["']([^"']+)["']/i
  ];
  for (const pat of tablePatterns) {
    const match = html.match(pat);
    if (match && !match[1].toLowerCase().includes('option')) {
      return stripTags(match[1]).trim().toUpperCase();
    }
  }

  // 패턴 D: url meta (최후의 보루)
  const urlMeta = html.match(/<meta[^>]+property=["']og:url["'][^>]+content=["']([^"']+)["']/i);
  if (urlMeta) {
    const url = urlMeta[1];
    const pathPart = url.split('/product/')[1] || '';
    const codeMatch = pathPart.match(/([a-zA-Z]{2}\d{4,})/);
    if (codeMatch) return codeMatch[1].toUpperCase();
  }

  return null;
}

// --- 가격 추출 로직 ---
const SALE_LABELS = [
  /할인가[^0-9]{0,30}(\d{1,3}(?:,\d{3})*|\d+)\s*원/i,
  /판매가[^0-9]{0,30}(\d{1,3}(?:,\d{3})*|\d+)\s*원/i,
  /최종결제가[^0-9]{0,30}(\d{1,3}(?:,\d{3})*|\d+)\s*원/i,
  /구매가[^0-9]{0,30}(\d{1,3}(?:,\d{3})*|\d+)\s*원/i,
];
const ORIG_LABELS = [
  /소비자가[^0-9]{0,30}(\d{1,3}(?:,\d{3})*|\d+)\s*원/i,
  /정가[^0-9]{0,30}(\d{1,3}(?:,\d{3})*|\d+)\s*원/i,
  /원가[^0-9]{0,30}(\d{1,3}(?:,\d{3})*|\d+)\s*원/i,
  /판매가\s*\(정상가\)[^0-9]{0,30}(\d{1,3}(?:,\d{3})*|\d+)\s*원/i,
];
function findFirstPrice(text, patterns) {
  for (const re of patterns) {
    const m = text.match(re);
    if (m) return num(m[1], null);
  }
  return null;
}
function parseListedPrice(html) {
  const text = stripTags(html);
  const sale = findFirstPrice(text, SALE_LABELS);
  if (sale) return sale;
  const m = text.match(/(\d{1,3}(?:,\d{3})*|\d+)\s*원/);
  return m ? num(m[1], null) : null;
}
function parseOriginalPrice(html) {
  const text = stripTags(html);
  return findFirstPrice(text, ORIG_LABELS);
}

// ── 실행 로직 ────────────────────────────────────────
const html = String($json.html ?? '');
const idx = (typeof $itemIndex === 'number') ? $itemIndex : 0;
const fromFlatten = (((($items('Flatten', 0, 0) || [])[idx] || {}).json) || {});
const prev = { ...fromFlatten, ...$json };

// ===== 사전 판매(manual) 상품 분기 (B안: 기존 흐름 유지, manual은 크롤링 결과 대신 시트값 사용) =====
const __isActive = (v) => {
  const s = String(v ?? '').trim().toUpperCase();
  return s === 'TRUE' || s === '1' || s === 'Y' || s === 'YES';
};
const __isManual = String(prev.product_mode || '').trim().toLowerCase() === 'manual'
                || String(prev.manual_keyword || '').trim() !== '';

if (__isManual) {
  // manual_products active 상품 찾기
  let __mp = [];
  try { __mp = $('GS: Get Manual Products').all().map(r => r.json); } catch (e) {}
  const __mkey = String(prev.manual_keyword || '').trim();
  const __prod = __mp.find(p => __isActive(p.active) && String(p.keyword ?? '').trim() === __mkey) || null;

  // discount_rules
  let __rules = [];
  try { __rules = $('Google Sheets').all().map(r => r.json); } catch (e) {}

  // 크루
  let __crew = '일반';
  try {
    const wh = $('Webhook1').first().json.body || $('Webhook1').first().json;
    if (wh.groups && wh.groups[0] && wh.groups[0].crew_name) __crew = String(wh.groups[0].crew_name).trim();
  } catch (e) {}

  // 상품명 / 소비자가 (original_price 없으면 null -> 소비자가 표기 안 함)
  const __name = String((__prod && (__prod.product_name || __prod.keyword)) || __mkey || '').trim();
  const __orig = __prod ? num(__prod.original_price, null) : null;
  const __display = (__orig && __orig > 0) ? __orig : null;

  // discount_rules 키워드 매칭 (기존 URL 방식과 동일하게 공백 제거 + 대문자 부분일치)
  const __target = (__name + ' ' + __mkey).replace(/\s+/g, '').toUpperCase();
  const __rule = __rules.find(rule => {
    const k = String(rule.keyword || '').replace(/\s+/g, '').toUpperCase();
    return k && __target.includes(k);
  });

  let __final = 0, __mode = null, __label = '0%', __rate = 0;
  let __supplyRate = 0, __supplyPrice = (__display || 0);
  let __debug = __prod ? 'manual: no rule matched' : 'manual: product not found/inactive';

  if (__rule) {
    const __cf = `fixed_price_${__crew}`;
    const __cr = `discount_rate_${__crew}`;

    // 영산 공급용 기본 할인율 (크루 무시, discount_rate 기준)
    const __base = Number(__rule.discount_rate || 0);
    __supplyRate = __base * 100;
    __supplyPrice = (__base > 0 && __display) ? Math.round(__display * (1 - __base)) : (__display || 0);
    __debug = `Manual Matched: ${__rule.keyword}, Crew: ${__crew}`;

    const __crewFixed = num0(__rule[__cf]);
    const __commonFixed = num0(__rule.fixed_price);

    if (__crewFixed > 0) {
      // 1순위: 크루별 고정가 (original_price 없어도 OK)
      __final = __crewFixed; __mode = 'fixed'; __label = `고정가 (${__crew})`;
    } else if (__commonFixed > 0) {
      // 2순위: 공통 고정가 (original_price 없어도 OK)
      __final = __commonFixed; __mode = 'fixed'; __label = '고정가';
    } else {
      // 3/4순위: 크루별 할인율 -> 공통 할인율 (display_price 필요)
      const __raw = __rule[__cr] || __rule.discount_rate || 0;
      const __rr = Number(__raw || 0);
      if (__rr > 0 && __display) {
        __final = Math.round(__display * (1 - __rr));
        __mode = 'auto_rule';
        __rate = __rr * 100;
        const __hasCrew = Number(__rule[__cr]) > 0;
        __label = __hasCrew ? `${__rate}% (${__crew})` : `${__rate}% (자동)`;
      }
      // __rr > 0 이지만 display(소비자가)가 없으면 __final = 0 -> price_found false (가격 계산 불가)
    }
  }

  return {
    json: {
      ...prev,
      product_url: '',
      name: __name,
      original_price: (__orig && __orig > 0) ? __orig : null,
      listed_price: 0,
      display_price: __display,
      price: Number(__final || 0),
      discount_mode: __mode,
      discount_label: __label,
      discount_rate: Number(__rate || 0),
      supply_rate: __supplyRate,
      supply_price: __supplyPrice,
      price_found: Number(__final) > 0,
      match_debug: __debug
    }
  };
}

// 1. 이름 정밀 확보
let nameRaw = parseName(html);
let name = cleanBrandName(nameRaw);

// 2. SKU 정밀 수색 및 결합 (함수명 일치 완료)
const foundSKU = extractSKU(html, name);

// 이름에 괄호가 포함되어 있지 않다면, 찾아낸 SKU를 뒤에 붙여줌
if (foundSKU && !name.includes(`(${foundSKU})`)) {
  name = name.replace(/\([^)]+\)$/, '').trim();
  name = `${name} (${foundSKU})`;
}

// 3. 가격 파싱
const listedParsed   = num0(parseListedPrice(html));   
const originalParsed = num0(parseOriginalPrice(html)); 

// 4. [할인 규칙] 구글 시트 데이터 가져오기
let rules = [];
try {
  rules = $('Google Sheets').all().map(r => r.json);
} catch (e) {}

// 5. 가격 결정 로직
// ✅ 웹훅 데이터에서 소속(crew_name) 정보 가져오기
let userCrew = '일반';
try {
  const whData = $('Webhook1').first().json.body || $('Webhook1').first().json;
  if (whData.groups && whData.groups[0] && whData.groups[0].crew_name) {
    userCrew = String(whData.groups[0].crew_name).trim();
  }
} catch (e) {}

const inputMode = prev.discount_mode; 
const inputRate = Number(prev.discount_rate || 0);
const inputFixed = Number(prev.fixed_price || 0);

let original_price = originalParsed || (Number.isFinite(prev.original_price) ? num0(prev.original_price) : null) || null;
const listed_price = listedParsed || (Number.isFinite(prev.price) ? num0(prev.price) : null) || 0;
const display_price = original_price || listed_price; 

let final_price = listed_price;
let final_mode = null;
let final_label = '0%';
let final_rate = 0;
let match_debug = null;

// ✅ 추가: 영산 공급가(기본 할인가) 저장용 변수 세팅
let supply_rate = 0;
let supply_price = listed_price;

// A. 수동 모드 우선
if (inputMode === 'fixed' && inputFixed > 0) {
  final_price = inputFixed;
  final_mode = 'fixed';
  final_label = '고정';
} else if (inputMode === 'percent' && inputRate > 0) {
  final_price = Math.round(display_price * (1 - inputRate / 100));
  final_mode = 'percent';
  final_label = `${inputRate}%`;
  final_rate = inputRate;
} 
// B. 자동 규칙 매칭 (✅ 고객 할인가 & 영산 공급가 동시 계산)
else {
  const rawTarget = (name + ' ' + (foundSKU || '') + ' ' + (prev.product_url || ''));
  const targetStr = rawTarget.replace(/\s+/g, '').toUpperCase(); 

  const matchedRule = rules.find(rule => {
    const keyword = String(rule.keyword || '').replace(/\s+/g, '').toUpperCase();
    return keyword && targetStr.includes(keyword);
  });

  if (matchedRule) {
    const crewFixedKey = `fixed_price_${userCrew}`;
    const crewRateKey  = `discount_rate_${userCrew}`;

    // 영산 공급용 기본 할인율 (크루 무시, 무조건 discount_rate 기준)
    const baseRate = Number(matchedRule.discount_rate || 0);
    supply_rate = baseRate * 100;
    supply_price = baseRate > 0 ? Math.round(display_price * (1 - baseRate)) : display_price;

    match_debug = `Matched: ${matchedRule.keyword}, Crew: ${userCrew}`;

    const crewFixedPrice   = num0(matchedRule[crewFixedKey]);
    const commonFixedPrice = num0(matchedRule.fixed_price);

    if (crewFixedPrice > 0) {
      // 1순위: 크루별 고정가
      final_price = crewFixedPrice;
      final_mode  = 'fixed';
      final_label = `고정가 (${userCrew})`;
      final_rate  = 0;
    } else if (commonFixedPrice > 0) {
      // 2순위: 공통 고정가
      final_price = commonFixedPrice;
      final_mode  = 'fixed';
      final_label = '고정가';
      final_rate  = 0;
    } else {
      // 3/4순위: 크루별 할인율 → 공통 할인율
      const rawRate  = matchedRule[crewRateKey] || matchedRule.discount_rate || 0;
      const ruleRate = Number(rawRate || 0);

      if (ruleRate > 0) {
        final_price = Math.round(display_price * (1 - ruleRate));
        final_mode  = 'auto_rule';
        final_rate  = ruleRate * 100;
        const hasCrewRate = Number(matchedRule[crewRateKey]) > 0;
        final_label = hasCrewRate ? `${final_rate}% (${userCrew})` : `${final_rate}% (자동)`;
      }
    }
  }
}

const price_found = Number(final_price) > 0;

// ✅ 계산된 공급가 데이터를 밖으로 내보냅니다.
return {
  json: {
    ...prev,
    name, 
    original_price: original_price ?? null,
    listed_price,
    display_price,
    price: Number(final_price || 0),
    discount_mode: final_mode,
    discount_label: final_label,
    discount_rate: Number(final_rate || 0),
    supply_rate: supply_rate,     // 👉 영산 기준 공급 할인율 추가
    supply_price: supply_price,   // 👉 영산 기준 공급 단가 추가
    price_found,
    match_debug 
  }
};

// Webhook body에서 crew 읽기 (GS 결과에 덮이지 않도록 원본 참조)
const webhookData = $('Webhook: Mall Notice').first().json;
const body = webhookData.body || webhookData;
const crew = String(body.crew || '').trim();

// notices 탭 전체 행
const rows = $('GS: Get Notices').all().map(r => r.json);

const isActive = (v) => {
  const s = String(v ?? '').trim().toUpperCase();
  return s === 'TRUE' || s === '1' || s === 'Y' || s === 'YES';
};

const matched = rows.find(r =>
  String(r.crew || '').trim() === crew &&
  isActive(r.active) &&
  String(r.notice_html || '').trim()
);

// ── 평문 → HTML 변환 유틸 (모든 입력은 평문으로 간주) ────────
function escapeHtml(input) {
  return String(input ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function linkify(input) {
  return String(input || '').replace(
    /(https?:\/\/[^\s<]+)/g,
    '<a href="$1" target="_blank" rel="noopener">$1</a>'
  );
}

function plainTextToNoticeHtml(input) {
  const raw = String(input || '').replace(/\r\n/g, '\n').trim();
  if (!raw) return '';

  const lines = raw.split('\n');
  const html = [];
  let inList = false;
  let inPre  = false;
  const preLines = [];

  const closeList = () => {
    if (inList) { html.push('</ul>'); inList = false; }
  };
  const flushPre = () => {
    if (inPre) {
      html.push('<pre>' + preLines.map(escapeHtml).join('\n') + '</pre>');
      inPre = false;
      preLines.length = 0;
    }
  };

  for (const originalLine of lines) {
    const line = String(originalLine || '').trim();

    if (!line) {
      if (inPre) { preLines.push(''); }
      else { closeList(); }
      continue;
    }

    // "6. 기타 안내"가 나오면 양식 pre 블록 종료
    if (inPre && /^6\.\s*/.test(line)) {
      flushPre();
    }

    if (inPre) {
      preLines.push(originalLine);
      continue;
    }

    // 양식 블록 시작
    if (
      line.includes('교환 및 반품 요청 양식') ||
      line.includes('\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014') ||
      line === '-교환 및 반품-' ||
      line === '-수선&심의접수-'
    ) {
      closeList();
      inPre = true;
      preLines.push(originalLine);
      continue;
    }

    // 메인 제목
    if (line === '공동구매 필독 공지사항') {
      closeList();
      html.push('<h2>' + linkify(escapeHtml(line)) + '</h2>');
      continue;
    }

    // 숫자 제목
    if (/^\d+\.\s+/.test(line)) {
      closeList();
      html.push('<h3>' + linkify(escapeHtml(line)) + '</h3>');
      continue;
    }

    // 괄호 제목
    if (/^\(.+\)$/.test(line)) {
      closeList();
      html.push('<h4>' + linkify(escapeHtml(line)) + '</h4>');
      continue;
    }

    // 리스트
    if (/^[-*]\s*/.test(line)) {
      if (!inList) { html.push('<ul>'); inList = true; }
      const item = line.replace(/^[-*]\s*/, '');
      html.push('<li>' + linkify(escapeHtml(item)) + '</li>');
      continue;
    }

    closeList();
    html.push('<p>' + linkify(escapeHtml(line)) + '</p>');
  }

  closeList();
  flushPre();

  return html.join('\n');
}

if (matched) {
  const rawNotice = String(matched.notice_html || '');
  return [{
    json: {
      ok: true,
      crew,
      title: String(matched.title || ''),
      notice_html: plainTextToNoticeHtml(rawNotice),
      updated_at: String(matched.updated_at || '')
    }
  }];
}

return [{
  json: {
    ok: false,
    crew,
    message: '공지사항이 없습니다.',
    notice_html: ''
  }
}];

// manual_products 탭에서 active 상품만 정리해서 반환
const rows = $('GS: Load Manual Products').all().map(r => r.json);

const isActive = (v) => {
  const s = String(v ?? '').trim().toUpperCase();
  return s === 'TRUE' || s === '1' || s === 'Y' || s === 'YES';
};
const num = (v) => {
  const n = Number(String(v ?? '').replace(/[^\d.-]/g, ''));
  return Number.isFinite(n) ? n : null;
};

const products = rows
  .filter(r => isActive(r.active) && String(r.keyword ?? '').trim() !== '')
  .map(r => ({
    keyword: String(r.keyword).trim(),
    product_name: String(r.product_name ?? '').trim() || String(r.keyword).trim(),
    original_price: num(r.original_price),
    _sort: num(r.sort_order),
  }))
  .sort((a, b) => {
    const sa = a._sort, sb = b._sort;
    if (sa == null && sb == null) return 0;
    if (sa == null) return 1;
    if (sb == null) return -1;
    return sa - sb;
  })
  .map(({ _sort, ...rest }) => rest);

return [{ json: { ok: true, products } }];
